"use strict";parserFactory.register("wetriedtls.com",()=>new WetriedTlsParser);class WetriedTlsParser extends Parser{constructor(){super(),this.minimumThrottle=2e3,this.chaptersSourceTitleMap=new Map}async getChapterUrls(){return(await HttpClient.fetchJson("https://api.wetriedtls.com/chapters/"+this.id+"?page=1&perPage=9999&order=asc")).json.data.map(t=>{const e={sourceUrl:`${"https://wetriedtls.com/series/"+t.series.series_slug}/${t.chapter_slug}`,title:t.chapter_title};return this.chaptersSourceTitleMap.set(e.sourceUrl,e.title),e})}async loadEpubMetaInfo(t){const e=t.querySelector("section .text-xl").textContent.trim();let r=(await HttpClient.fetchJson("https://api.wetriedtls.com/query?adult=true&query_string="+e)).json;if(0===r.data.length)throw new Error("No series found for the given title.");const i=r.data[0];this.id=i.id,this.title=i.title,this.thumbnail=i.thumbnail,this.description=i.description}async fetchChapter(t){const e=(await HttpClient.wrapFetch(t)).responseXML,r=Array.from(e.querySelectorAll("script")).map(t=>t.textContent).filter(t=>t.includes("self.__next_f.push(")).map(t=>{const e=t.slice(19,-1);try{return JSON.parse(e)}catch{return null}}).filter(Boolean).find(([t,e])=>1===t&&"string"==typeof e&&/<p\b[^>]*>|<div\b[^>]*>|<br\b[^>]*>|<\/?strong\b[^>]*>/i.test(e)&&e.length>1e3);if(!r)throw new Error("No HTML chapter content found.");return this.buildChapter(r[1],t)}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e),i=util.sanitize(t);return util.moveChildElements(i.body,r.content),r.dom}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(){return this.title.trim()}extractAuthor(t){if(!t)return super.extractAuthor(t);const e=Array.from(t.querySelectorAll("span.text-muted-foreground")).find(t=>"Author"===t.innerText.trim()),r=e?.parentElement?.querySelector(":scope span:last-child");return r?.innerText||super.extractAuthor(t)}extractDescription(){return this.description.trim()}findCoverImageUrl(){return this.thumbnail}findChapterTitle(t){return this.chaptersSourceTitleMap.get(t.baseURI)}}